import React, { useEffect, useState } from "react";
import CodeMirror from "@uiw/react-codemirror";
import { html } from "@codemirror/lang-html";
import { css } from "@codemirror/lang-css";
import { javascript } from "@codemirror/lang-javascript";
import "./App.css";

function App() {
  const [tab, setTab] = useState("html");

  const [htmlCode, setHtml] = useState("<h1>Hello</h1>");
  const [cssCode, setCss] = useState("h1{color:red}");
  const [jsCode, setJs] = useState("");

  const [projects, setProjects] = useState([]);
  const [currentIndex, setCurrentIndex] = useState(null);

  const [run, setRun] = useState(true);

  // LOAD PROJECTS
  useEffect(() => {
    const data = JSON.parse(localStorage.getItem("projects")) || [];
    setProjects(data);
  }, []);

  // SAVE PROJECTS
  useEffect(() => {
    localStorage.setItem("projects", JSON.stringify(projects));
  }, [projects]);

  // NEW PROJECT
  const newProject = () => {
    const proj = { html: "", css: "", js: "" };
    setProjects([...projects, proj]);
    setCurrentIndex(projects.length);
    setHtml("");
    setCss("");
    setJs("");
  };

  // LOAD PROJECT
  const loadProject = (i) => {
    setCurrentIndex(i);
    setHtml(projects[i].html);
    setCss(projects[i].css);
    setJs(projects[i].js);
  };

  // SAVE CURRENT
  const saveProject = () => {
    if (currentIndex === null) return;
    const updated = [...projects];
    updated[currentIndex] = {
      html: htmlCode,
      css: cssCode,
      js: jsCode,
    };
    setProjects(updated);
  };

  // COPY
  const copyCode = () => {
    const code =
      tab === "html" ? htmlCode :
      tab === "css" ? cssCode : jsCode;

    navigator.clipboard.writeText(code);
  };

  // DOWNLOAD
  const downloadCode = () => {
    const file = new Blob(
      [htmlCode + "<style>" + cssCode + "</style><script>" + jsCode + "</script>"],
      { type: "text/html" }
    );
    const a = document.createElement("a");
    a.href = URL.createObjectURL(file);
    a.download = "project.html";
    a.click();
  };

  // CLEAR OUTPUT
  const clearOutput = () => {
    setRun(false);
  };

  // PREVIEW OUTPUT
  const output = `
    <html>
      <style>${cssCode}</style>
      <body>
        ${htmlCode}
        <script>${jsCode}<\/script>
      </body>
    </html>
  `;

  // EDITOR LANGUAGE
  const getLang = () => {
    if (tab === "html") return html();
    if (tab === "css") return css();
    return javascript();
  };

  return (
    <div className="app">

      {/* SIDEBAR */}
      <div className="sidebar">
        <h3>Projects</h3>
        <button onClick={newProject}>+ New</button>

        {projects.map((p, i) => (
          <div key={i} onClick={() => loadProject(i)}>
            Project {i + 1}
          </div>
        ))}
      </div>

      {/* MAIN */}
      <div className="main">

        {/* TOPBAR */}
        <div className="topbar">
          <h2>CodeSnip Pro</h2>

          <div>
            <button onClick={saveProject}>Save</button>
            <button onClick={copyCode}>Copy</button>
            <button onClick={downloadCode}>Download</button>
          </div>
        </div>

        {/* TABS */}
        <div className="tabs">
          <button onClick={() => setTab("html")}>HTML</button>
          <button onClick={() => setTab("css")}>CSS</button>
          <button onClick={() => setTab("js")}>JS</button>
          <button onClick={() => setTab("python")}>Python</button>
          <button onClick={() => setTab("java")}>Java</button>
        </div>

        {/* MAIN EDITOR + OUTPUT */}
        <div className="container">

          {/* EDITOR */}
          <div className="editor">
            <CodeMirror
              value={tab === "html" ? htmlCode : tab === "css" ? cssCode : jsCode}
              height="100%"
              extensions={[getLang()]}
              onChange={(value) => {
                if (tab === "html") setHtml(value);
                if (tab === "css") setCss(value);
                if (tab === "js") setJs(value);
              }}
            />
          </div>

          {/* OUTPUT */}
          <div className="preview">

            <div className="outputControls">
              <button className="runBtn" onClick={() => setRun(true)}>
                ▶ Run
              </button>

              <button className="clearBtn" onClick={clearOutput}>
                Clear
              </button>
            </div>

            <iframe
              className="outputBox"
              srcDoc={run ? output : ""}
              title="preview"
              sandbox="allow-scripts"
            />

          </div>

        </div>

      </div>
    </div>
  );
}

export default App;
